29 +	if pCtx.DataSourceInstanceSettings != nil {
30 +		p = append(p, "dsName", pCtx.DataSourceInstanceSettings.Name)
31 +		p = append(p, "dsUID", pCtx.DataSourceInstanceSettings.UID)
32 +	}
